fragment ActorFields on Actor {
    id
    name
    handle
    avatarUrl
}

fragment MediaFields on PostMedium {
    id
    url
    thumbnailUrl
    alt
    height
    width
    type
}

fragment EngagementStatsFields on PostEngagementStats {
    replies
    reactions
    shares
    quotes
}

fragment PostFields on Post {
    __typename
    id
    name
    published
    summary
    content
    excerpt
    url
    iri
    viewerHasShared
    actor {
        ...ActorFields
    }
    media {
        ...MediaFields
    }
    link {
        title
        description
        url
        siteName
        author
        image {
            url
            alt
            width
            height
        }
        creator {
            ...ActorFields
        }
    }
    engagementStats {
        ...EngagementStatsFields
    }
    mentions(first: 20) {
        edges {
            node {
                handle
            }
        }
    }
    quotedPost {
        ...SharedPostFields
    }
    reactionGroups {
        __typename
        ... on EmojiReactionGroup {
            emoji
            reactors(first: 20) {
                totalCount
                viewerHasReacted
            }
        }
        ... on CustomEmojiReactionGroup {
            customEmoji {
                id
                name
                imageUrl
            }
            reactors(first: 20) {
                totalCount
                viewerHasReacted
            }
        }
    }
}

fragment SharedPostFields on Post {
    __typename
    id
    name
    published
    summary
    content
    excerpt
    url
    iri
    viewerHasShared
    actor {
        ...ActorFields
    }
    media {
        ...MediaFields
    }
    engagementStats {
        ...EngagementStatsFields
    }
    mentions(first: 20) {
        edges {
            node {
                handle
            }
        }
    }
}

query PublicTimeline($after: String) {
    publicTimeline(first: 20, after: $after) {
        edges {
            cursor
            node {
                ...PostFields
                sharedPost {
                    ...SharedPostFields
                }
            }
        }
        pageInfo {
            hasNextPage
            endCursor
        }
    }
}

query LocalTimeline($after: String) {
    publicTimeline(local: true, first: 20, after: $after) {
        edges {
            cursor
            node {
                ...PostFields
                sharedPost {
                    ...SharedPostFields
                }
            }
        }
        pageInfo {
            hasNextPage
            endCursor
        }
    }
}

query PersonalTimeline($after: String) {
    personalTimeline(first: 20, after: $after) {
        edges {
            cursor
            lastSharer {
                ...ActorFields
            }
            sharersCount
            node {
                ...PostFields
