                            publishedArticleUrl = article.url
                        )
                    }
                }
                .onFailure { error ->
                    _uiState.update {
                        it.copy(
                            error = error.message,
                            isPublishing = false
                        )
                    }
                }
        }
    }

    private fun detectLanguage(text: String) {
        if (text.isBlank() || text.length < 20) return

        try {
